import dateutil.parser as parser

def parse_date_flexible(date_str):
    if pd.isna(date_str) or date_str == 'unknown':
        return pd.NaT
    try:
        return pd.to_datetime(date_str)
    except:
        try:
            return parser.parse(date_str)
        except:
            return pd.NaT

df['signup_datetime'] = df['signup_date'].apply(parse_date_flexible)

print(f"Successfully parsed: {df['signup_datetime'].notna().sum()} out of {len(df)}")
print(f"\nRemaining unparsed: {df['signup_datetime'].isna().sum()}")
if df['signup_datetime'].isna().sum() > 0:
    print(df[df['signup_datetime'].isna()]['signup_date'].value_counts())

# Extract year, quarter, month for campaign analysis
